const myPromise = new Promise((resolve, reject) => {
  setTimeout(() => {
    const success = true; // Simulate operation result
    if (success) {
      resolve('Operation successful!');
    } else {
      reject('Something went wrong.');
    }
  }, 2000);
});

myPromise
  .then(result => {
    console.log(result); // Logs after 2 seconds: Operation successful!
  })
  .catch(error => {
    console.error(error);
  });

type User = {
  name: string;
  age: number;
};

const user: User = { name: 'Alice', age: 25 };

// This line will cause an error:
// Property 'email' does not exist on type 'User'.
console.log(user.email);

interface UserInterface {
  name: string;
  age: number;
}

// You can extend interfaces
interface ExtendedUserInterface extends UserInterface {
  email: string;
}

// Type alias for an object
type UserType = {
  name: string;
  age: number;
};

// Type aliases can also create unions
type Status = "active" | "inactive" | "pending";

// Example usage
const user1: UserInterface = { name: "Alice", age: 25 };
const user2: UserType = { name: "Bob", age: 30 };
const currentStatus: Status = "active";

interface User {
  name: string;
  age?: number;
}

function getUser(): User | undefined {
  // Sometimes returns undefined
  return Math.random() > 0.5 ? { name: 'Alice' } : undefined;
}

const user = getUser();
console.log(user.name); // Error: Cannot read properties of undefined (reading 'name')

const user = getUser();

// Using optional chaining (?.) to avoid error when user is undefined
console.log(user?.name);

// Or with a traditional check
if (user !== undefined) {
  console.log(user.name);
}

def simple_decorator(func):
    def wrapper():
        print('Before the function runs')
        func()
        print('After the function runs')
    return wrapper

@simple_decorator
def say_hello():
    print('Hello!')

say_hello()

# Output:
# Before the function runs
# Hello!
# After the function runs

